function mkScores(base = 8.9) {
  return { c1: base + 0.1, c2: base, c3: base - 0.1, c4: base, c5: base - 0.2, overall: base };
}

function buildRaw(row, sortOrder) {
  const [slug, title, h1, intro, groupKey, wName, wSlug, wTag, wType, wPrice, wUrl, wSummary, r1, r2, r3, r4, r5, labels] = row;
  const rival = (r) => ({ slug: r[0], name: r[1], price: r[2], url: r[3], tagline: r[4], typeLabel: r[5] });
  return {
    sortOrder,
    categoryGroup: GROUPS[groupKey],
    slug,
    title: `${title} (2026)`,
    h1,
    intro,
    scoreLabels: labels,
    winner: { slug: wSlug, name: wName, tagline: wTag, typeLabel: wType, price: wPrice, url: wUrl, summary: wSummary, scores: mkScores(9.0) },
    rivals: [rival(r1), rival(r2), rival(r3), rival(r4), rival(r5)],
  };
}

